import { useSelector } from 'react-redux';
import { Link } from 'react-router-dom';

export default function HomePage() {
  const user = useSelector(s => s.auth.user);

  return (
    <div style={styles.wrap}>
      <div style={styles.hero}>
        <h1 style={styles.title}>Welcome to The Grand Table</h1>
        <p style={styles.sub}>Reserve your perfect dining experience</p>
        {!user && (
          <div style={styles.btns}>
            <Link to="/register" style={styles.primary}>Get Started</Link>
            <Link to="/login" style={styles.secondary}>Login</Link>
          </div>
        )}
        {user?.role === 'customer' && (
          <Link to="/reserve" style={styles.primary}>Make a Reservation</Link>
        )}
        {(user?.role === 'staff' || user?.role === 'admin') && (
          <Link to="/dashboard" style={styles.primary}>Go to Dashboard</Link>
        )}
      </div>
    </div>
  );
}

const styles = {
  wrap:      { minHeight: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 100%)' },
  hero:      { textAlign: 'center', color: '#fff', padding: 32 },
  title:     { fontSize: '2.5rem', marginBottom: 12 },
  sub:       { fontSize: '1.2rem', color: '#aaa', marginBottom: 32 },
  btns:      { display: 'flex', gap: 16, justifyContent: 'center' },
  primary:   { padding: '12px 28px', background: '#e94560', color: '#fff', borderRadius: 6, textDecoration: 'none', fontSize: '1rem' },
  secondary: { padding: '12px 28px', border: '2px solid #fff', color: '#fff', borderRadius: 6, textDecoration: 'none', fontSize: '1rem' },
};
